if __name__ == "__main__":
    logging.basicConfig(
        level=logging.INFO,
        format="%(asctime)s %(levelname)s %(message)s",
        datefmt="%H:%M:%S",
    )
    ap = argparse.ArgumentParser(description="Token watchdog daemon")
    ap.add_argument("--config", required=True)
    ap.add_argument("--once", action="store_true")
    args = ap.parse_args()

    wd = TokenWatchdog(args.config)
    if args.once:
        print(json.dumps(wd.poll_once(), indent=2))
    else:
        wd.run()
